rss.channel:

    {{- .Site.Title -}}


    {{- .Permalink -}}


    {{- .Site.Params.description | default .Site.Title -}}

Hugo -- gohugo.io
{{- with .Site.LanguageCode -}}

        {{- . -}}

{{- end -}}
{{- /* Resolve site author for RSS metadata */ -}}
{{- $sa := .Site.Params.author -}}
{{- $siteAuthorEmail := "" -}}
{{- $siteAuthorName := "" -}}
{{- if $sa -}}
    {{- if (isset $sa "email") -}}
        {{- $siteAuthorEmail = index $sa "email" -}}
    {{- end -}}
    {{- if (isset $sa "name") -}}
        {{- $siteAuthorName = index $sa "name" -}}
    {{- else -}}
        {{- $siteAuthorName = $sa -}}
    {{- end -}}
{{- end -}}
{{- with $siteAuthorEmail -}}

        {{- . }}{{ with $siteAuthorName }} ({{ . }}){{ end -}}


        {{- . }}{{ with $siteAuthorName }} ({{ . }}){{ end -}}

{{- end -}}
{{- with .Site.Copyright -}}

        {{- . -}}

{{- end -}}
{{- if not .Date.IsZero -}}

        {{- .Date.Format "Mon, 02 Jan 2006 15:04:05 -0700" -}}

{{- end -}}
{{ with .OutputFormats.Get "RSS" }}
    {{ printf "" .Permalink .MediaType | safeHTML }}
{{ end }}
{{- range where .Site.RegularPages "Type" "posts" | first (.Site.Params.home.rss | default 10) -}}
    {{- dict "Page" . "Site" .Site | partial "rss/item.html" -}}
{{- end -}}
